  if (typeof val === 'number') return BigInt(val);
  if (typeof val === 'string') return BigInt(val);
  if (val instanceof Uint8Array) return bytesToBigInt(val);
  if (val != null && typeof val.toString === 'function') return BigInt(val.toString());
