    chainId: toBigInt(auth.chainId ?? auth.chain_id),
    address: normalizeAddress(auth.address),
    nonce:   toBigInt(auth.nonce),
    y:       toBigInt(auth.y ?? auth.y_parity ?? 0),
    r:       toBigInt(auth.r),
