    address: bytesToHex(addressBytes).toLowerCase(),
    nonce:   bytesToBigInt(nonceBytes),
    y:       bytesToBigInt(yBytes),
    r:       bytesToBigInt(rBytes),
    s:       bytesToBigInt(sBytes),
