      hasTransferFrom: 0.9,
      hasTransfer: 0.6,
      valueFlowsToAttacker: 0.95,
      isMulticall: 0.1,
      proxyPattern: 0.0,
      usesPermit: 1.0,
      callsExternalContracts: 0.5,
      freshSpender: 0.7,
      selectorCount: 0.2,
      ethValueNonZero: 0.4,
